import React from 'react';
import { Linking, Platform } from 'react-native';
import * as LinkingUtil from 'expo-linking';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

// Define your custom linking config
const linking = {
  prefixes: [LinkingUtil.makeUrl('/')],
  config: {
    screens: {
      Root: {
        path: 'root',
        parse: {
          screen: 'HomeScreen'
        }
      },
      Profile: {
        path: 'profile/:id',
        parse: {
          screen: 'ProfileScreen',
          id: undefined,
        }
      },
      PaymentConfirm: {
        path: 'payment/confirm',
        parse: {
          screen: 'PaymentConfirmScreen'
        }
      }
    }
  }
};

LinkingUtil.setUpAfterDeepLink(linking);

const Stack = createStackNavigator();

function App() {
  return (
    <NavigationContainer linking={linking}>
      <Stack.Navigator initialRouteName="Root">
        <Stack.Screen name="HomeScreen" component={HomeScreen} />
        <Stack.Screen name="ProfileScreen" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirmScreen" component={PaymentConfirmScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
}

// Your screens here (HomeScreen, ProfileScreen, PaymentConfirmScreen)

export default App;